import os
import time
import secrets
from typing import Dict, Optional

from flask import Flask, request, jsonify
from eth_account.messages import encode_defunct
from web3 import Web3

app = Flask(__name__)

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
ISSUED_NONCES: Dict[str, Dict[str, float]] = {}
SESSIONS: Dict[str, Dict[str, float]] = {}

w3 = Web3()


def now_ts() -> int:
    return int(time.time())


def normalize_address(address: str) -> str:
    return Web3.to_checksum_address(address)


def cleanup_expired_nonces() -> None:
    current = now_ts()
    expired = [
        addr for addr, data in ISSUED_NONCES.items()
        if current - data["issued_at"] > NONCE_TTL_SECONDS
    ]
    for addr in expired:
        ISSUED_NONCES.pop(addr, None)


def issue_nonce(address: str) -> str:
    cleanup_expired_nonces()
    nonce = secrets.token_urlsafe(24)
    ISSUED_NONCES[address] = {
        "nonce": nonce,
        "issued_at": now_ts(),
    }
    return nonce


def get_nonce(address: str) -> Optional[str]:
    cleanup_expired_nonces()
    entry = ISSUED_NONCES.get(address)
    if not entry:
        return None
    return entry["nonce"]


def consume_nonce(address: str) -> None:
    ISSUED_NONCES.pop(address, None)


def create_session(address: str) -> str:
    token = secrets.token_urlsafe(32)
    SESSIONS[token] = {
        "address": address,
        "created_at": now_ts(),
    }
    return token


def recover_signer(message: str, signature: str) -> str:
    encoded_message = encode_defunct(text=message)
    return w3.eth.account.recover_message(encoded_message, signature=signature)


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


@app.route("/auth/nonce", methods=["POST"])
def auth_nonce():
    data = request.get_json(silent=True) or {}
    address = data.get("address")

    if not address:
        return jsonify({"error": "address is required"}), 400

    try:
        address = normalize_address(address)
    except Exception:
        return jsonify({"error": "invalid ethereum address"}), 400

    nonce = issue_nonce(address)
    message = f"Sign this message to authenticate.\n\nAddress: {address}\nNonce: {nonce}"

    return jsonify({
        "address": address,
        "nonce": nonce,
        "message": message,
        "expires_in": NONCE_TTL_SECONDS,
    }), 200


@app.route("/auth/verify", methods=["POST"])
def auth_verify():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    signature = data.get("signature")
    message = data.get("message")

    if not address or not signature or not message:
        return jsonify({"error": "address, message, and signature are required"}), 400

    try:
        address = normalize_address(address)
    except Exception:
        return jsonify({"error": "invalid ethereum address"}), 400

    expected_nonce = get_nonce(address)
    if not expected_nonce:
        return jsonify({"error": "no valid nonce found for address"}), 400

    expected_message = f"Sign this message to authenticate.\n\nAddress: {address}\nNonce: {expected_nonce}"
    if message != expected_message:
        return jsonify({"error": "message does not match issued challenge"}), 400

    try:
        recovered = normalize_address(recover_signer(message, signature))
    except Exception:
        return jsonify({"error": "invalid signature"}), 400

    if recovered != address:
        return jsonify({"error": "signature verification failed", "recovered_address": recovered}), 401

    consume_nonce(address)
    session_token = create_session(address)

    return jsonify({
        "authenticated": True,
        "address": address,
        "session_token": session_token,
    }), 200


@app.route("/auth/session", methods=["GET"])
def auth_session():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "missing bearer token"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    session = SESSIONS.get(token)
    if not session:
        return jsonify({"authenticated": False}), 401

    return jsonify({
        "authenticated": True,
        "address": session["address"],
        "created_at": session["created_at"],
    }), 200


@app.route("/auth/logout", methods=["POST"])
def auth_logout():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "missing bearer token"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    SESSIONS.pop(token, None)

    return jsonify({"logged_out": True}), 200


